import React from 'react';
import './Education.css';

const Education = () => {
  return (
    <section className="education">
      <h2>Education</h2>
      <div className="education-item">
        <h3>Bachelor of Science in Information Technology (Specialization in Software Engineering)</h3>
        <p>Sri Lanka Institute of Information Technology (SLIIT), Malabe</p>
        <p>Cumulative GPA: 3.00</p>
      </div>
      <div className="education-item">
        <h3>GCE A/L (Physical science)</h3>
        <p>Kegalle Maha Vidyalaya</p>
        <p>Result - BBC</p>
      </div>
    </section>
  );
}

export default Education;
